  #===============================================================
  LAYER
		NAME 'transmedia'
		TYPE LINE
		INCLUDE "datashare.inc"		
		DATA 'geom FROM rjio_transmedia USING UNIQUE id USING srid=4326'	
		METADATA
			'ows_title' 'transmedia'
		END
		STATUS ON
		TRANSPARENCY 100
		PROJECTION
			'proj=longlat'
			'datum=WGS84'
			'no_defs'
		END		

		CLASS 
			NAME "transmedia"						
		     STYLE
				WIDTH 2
				COLOR 156 5 128				                						
			END				
		END			
	END
  
